package com.npci.UPISim.validation;

import com.npci.UPISim.dto.ReqPay;
import com.npci.UPISim.dto.Txn;

public final class ReqPayValidator {

    private ReqPayValidator() {}

    // ✅ RETURN error instead of throwing exception
    public static String validate(ReqPay reqPay) {

        if (reqPay.getHead() == null) {
            return "MISSING_FIELD:Head";
        }

        Txn txn = reqPay.getTxn();
        if (txn == null) {
            return "MISSING_FIELD:Txn";
        }

        if (txn.getType() == null) {
            return "MISSING_FIELD:Txn.type";
        }

        if (!ValidationRules.ALLOWED_TXN_TYPES.contains(txn.getType())) {
            return "INVALID_FIELD_VALUE:Txn.type=" + txn.getType();
        }

        if (txn.getPurpose() != null &&
                !ValidationRules.ALLOWED_PURPOSE_CODES.contains(txn.getPurpose())) {
            return "INVALID_FIELD_VALUE:Txn.purpose=" + txn.getPurpose();
        }

        if (txn.getInitiationMode() != null &&
                !ValidationRules.ALLOWED_INITIATION_MODES.contains(txn.getInitiationMode())) {
            return "INVALID_FIELD_VALUE:Txn.initiationMode=" + txn.getInitiationMode();
        }

        if (txn.getDelegate() == null) {
            return "MISSING_FIELD:Txn.delegate";
        }

        if (!ValidationRules.REQPAY_TXN_DELEGATE_ALLOWED_VALUES.contains(txn.getDelegate())) {
            return "INVALID_FIELD_VALUE:Txn.delegate=" + txn.getDelegate();
        }

        if (reqPay.getPayer() == null) {
            return "MISSING_FIELD:Payer";
        }

        if (reqPay.getPayer().getDevice() == null) {
            return "MISSING_FIELD:Payer.Device";
        }

        if (reqPay.getPayer().getDevice().getBindingMode() != null &&
                !ValidationRules.REQPAY_DEVICE_BINDINGMODE_ALLOWED_VALUES.contains(reqPay.getPayer().getDevice().getBindingMode())) {
            return "INVALID_FIELD_VALUE:Payer.Device.BINDINGMODE=" + reqPay.getPayer().getDevice().getBindingMode();
        }

        if (reqPay.getPayer().getDevice().getBindingMode() == null) {
            // Optional field, no validation needed
        } else if (!ValidationRules.REQPAY_PAYER_DEVICE_BINDINGMODE_ALLOWED_VALUES.contains(reqPay.getPayer().getDevice().getBindingMode())) {
            return "INVALID_FIELD_VALUE:Payer.Device.BINDINGMODE=" + reqPay.getPayer().getDevice().getBindingMode();
        }

        if (txn.getDelegate() != null && 
                !ValidationRules.REQPAY_TXN_DELEGATE_ALLOWED_VALUES.contains(txn.getDelegate())) {
            return "INVALID_FIELD_VALUE:Txn.delegate=" + txn.getDelegate();
        }

        if (txn.getDelegate() != null &&
                !ValidationRules.REQPAY_TXN_DELEGATE_ALLOWED_VALUES.contains(txn.getDelegate().toLowerCase())) {
            return "INVALID_FIELD_VALUE:Txn.delegate=" + txn.getDelegate();
        }

        if (txn.getNote() == null) {
            // Optional field, no validation needed
        } else if (!ValidationRules.REQPAY_HEAD_NOTE_ALLOWED_VALUES.contains(txn.getNote())) {
            return "INVALID_FIELD_VALUE:Txn.note=" + txn.getNote();
        }

        if (txn.getSubProduct() == null) {
            // Optional field, no validation needed
        } else if (!ValidationRules.REQPAY_TXN_SUBPRODUCT_ALLOWED_VALUES.contains(txn.getSubProduct())) {
            return "INVALID_FIELD_VALUE:Txn.SubProduct=" + txn.getSubProduct();
        }

        if (txn.getRemarks() == null) {
            // Optional field, no validation needed
        } else if (!ValidationRules.REQPAY_TXN_REMARKS_ALLOWED_VALUES.contains(txn.getRemarks())) {
            return "INVALID_FIELD_VALUE:Txn.Remarks=" + txn.getRemarks();
        }

        return null; // ✅ VALID
    }
}

